function compressImage(dataUrl: string, maxW=800, quality=0.7):Promise<string> {
  return new Promise(resolve => {
    const img = new Image();
    img.onload = () => {
      const scale = Math.min(1, maxW / img.width);
      const canvas = document.createElement("canvas");
      canvas.width = img.width * scale;
      canvas.height = img.height * scale;
      canvas.getContext("2d")!.drawImage(img, 0, 0, canvas.width, canvas.height);
      resolve(canvas.toDataURL("image/jpeg", quality));
    };
    img.src = dataUrl;
  });
}

function Lightbox({images,startIndex,onClose}:{images:string[];startIndex:number;onClose:()=>void}){
  const [idx,setIdx]=useState(startIndex);
  return(
    <div className="fixed inset-0 z-[100] bg-black flex flex-col" style={{WebkitTapHighlightColor:"transparent"}}>
      <div className="flex justify-between items-center px-4 py-3">
        <button type="button" onClick={onClose} style={{WebkitAppearance:"none"}} className="p-2 text-white"><X size={24}/></button>
        <span className="text-zinc-400 text-sm">{idx+1}/{images.length}</span>
        <div className="w-10"/>
      </div>
      <div className="flex-1 flex items-center justify-center relative px-2">
        <img src={images[idx]} alt="" className="max-h-full max-w-full object-contain rounded-2xl"/>
        {images.length>1&&<>
          <button type="button" onClick={()=>setIdx(i=>(i-1+images.length)%images.length)} style={{WebkitAppearance:"none"}} className="absolute right-2 top-1/2 -translate-y-1/2 p-3 bg-black/60 rounded-full text-white"><ChevronRight size={20}/></button>
          <button type="button" onClick={()=>setIdx(i=>(i+1)%images.length)} style={{WebkitAppearance:"none"}} className="absolute left-2 top-1/2 -translate-y-1/2 p-3 bg-black/60 rounded-full text-white"><ChevronLeft size={20}/></button>
        </>}
      </div>
      {images.length>1&&(
        <div className="flex gap-2 justify-center p-4 overflow-x-auto">
          {images.map((img,i)=>(
            <button key={i} type="button" onClick={()=>setIdx(i)} style={{WebkitAppearance:"none",borderColor:i===idx?BRAND:"transparent"}}
              className={`flex-shrink-0 w-14 h-14 rounded-xl overflow-hidden border-2 ${i!==idx?"opacity-50":""}`}>
              <img src={img} alt="" className="w-full h-full object-cover"/>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

