function ImagePicker({images,onChange,label}:{images:string[];onChange:(fn:(prev:string[])=>string[])=>void;label:string}){
  const add=async(e:React.ChangeEvent<HTMLInputElement>)=>{
    for(const file of Array.from(e.target.files||[])){
      const r=new FileReader();
      r.onloadend=async()=>{
        const compressed=await compressImage(r.result as string);
        onChange((prev:string[])=>[...prev,compressed]);
      };
      r.readAsDataURL(file);
    }
  };
  return(
    <div className="bg-zinc-800 border border-zinc-700 rounded-2xl px-4 py-3 space-y-3">
      <p className="text-zinc-400 text-sm">{label} ({images.length})</p>
      {images.length>0&&(
        <div className="flex gap-2 flex-wrap">
          {images.map((img,i)=>(
            <div key={i} className="relative w-16 h-16">
              <img src={img} alt="" className="w-full h-full object-cover rounded-xl"/>
              <button type="button" onClick={()=>onChange((imgs:string[])=>imgs.filter((_,idx)=>idx!==i))} style={{WebkitAppearance:"none"}}
                className="absolute -top-1 -left-1 w-5 h-5 bg-red-500 rounded-full flex items-center justify-center text-white"><X size={10}/></button>
            </div>
          ))}
        </div>
      )}
      <input type="file" accept="image/*" multiple onChange={add} className="w-full text-sm text-zinc-400" style={{fontSize:16}}/>
    </div>
  );
}

function ListManager({title,items,onSave,onBack,placeholder}:{title:string;items:string[];onSave:(v:string[])=>void;onBack:()=>void;placeholder:string}){
  const [list,setList]=useState(items);
  const [nv,setNv]=useState("");
  const [ei,setEi]=useState<number|null>(null);
  const [ev,setEv]=useState("");
  const add=()=>{const v=nv.trim();if(!v||list.includes(v))return;const u=[...list,v];setList(u);onSave(u);setNv("");};
  const rem=(i:number)=>{const u=list.filter((_,idx)=>idx!==i);setList(u);onSave(u);};
  const se=()=>{const v=ev.trim();if(!v)return;const u=list.map((x,i)=>i===ei?v:x);setList(u);onSave(u);setEi(null);};
  return(
    <div className="p-6 space-y-4">
      <button type="button" onClick={onBack} style={{WebkitAppearance:"none"}} className="text-zinc-400 text-sm flex items-center gap-1 mb-2"><ChevronRight size={14}/>رجوع</button>
      <h3 style={{color:BRAND}} className="text-lg font-black">{title}</h3>
      <div className="space-y-2">
        {list.map((item,i)=>(
          <div key={i} className="flex items-center gap-2 bg-zinc-800 rounded-2xl px-4 py-3">
            {ei===i?(<><input value={ev} onChange={e=>setEv(e.target.value)} className="flex-1 bg-transparent text-white outline-none" style={{fontSize:16}}/>
              <button type="button" onClick={se} style={{WebkitAppearance:"none"}} className="p-1 text-green-400"><Check size={16}/></button>
              <button type="button" onClick={()=>setEi(null)} style={{WebkitAppearance:"none"}} className="p-1 text-zinc-400"><X size={16}/></button></>
            ):(<><span className="flex-1 text-white font-medium">{item}</span>
              <button type="button" onClick={()=>{setEi(i);setEv(item);}} style={{WebkitAppearance:"none"}} className="p-1 text-zinc-400"><Edit2 size={14}/></button>
              <button type="button" onClick={()=>rem(i)} style={{WebkitAppearance:"none"}} className="p-1 text-red-400"><X size={14}/></button></>
            )}
          </div>
        ))}
      </div>
      <div className="flex gap-2">
        <input type="text" placeholder={placeholder} value={nv} onChange={e=>setNv(e.target.value)} onKeyDown={e=>e.key==="Enter"&&add()} className="flex-1 bg-zinc-800 border border-zinc-700 rounded-2xl px-4 py-3 text-white" style={{fontSize:16}}/>
        <button type="button" onClick={add} style={{backgroundColor:BRAND,WebkitAppearance:"none"}} className="px-4 py-3 rounded-2xl text-white font-bold"><Plus size={18}/></button>
      </div>
    </div>
  );
}

